class SimpleSensorDevice:
    """Example implementation of a simple sensor device"""
    
    def __init__(self, name="ESP32-Sensor"):
        self.ble_controller = BLEDeviceController(name)
        self.ble_controller.set_command_callback(self._on_command)
        self.ble_controller.set_config_callback(self._on_config)
        
        # Device state
        self.led_state = False
        self.relay_state = False
        self.mode = 0
        self.interval = 1000
        
        # Simulated sensor values
        self.temperature = 25.0
        self.humidity = 50.0
        self.light = 500
        
    def _on_command(self, command):
        """Handle control commands from mobile app"""
        if len(command) < 1:
            return
        
        cmd = command[0]
        
        if cmd == 0x01:  # LED ON
            self.led_state = True
            print("LED turned ON")
            self._update_status()
            
        elif cmd == 0x02:  # LED OFF
            self.led_state = False
            print("LED turned OFF")
            self._update_status()
            
        elif cmd == 0x03:  # Relay ON
            self.relay_state = True
            print("Relay turned ON")
            self._update_status()
            
        elif cmd == 0x04:  # Relay OFF
            self.relay_state = False
            print("Relay turned OFF")
            self._update_status()
            
        elif cmd == 0x05:  # Request sensor reading
            print("Sending sensor data")
            self._send_sensor_data()
            
        elif cmd == 0x06:  # Reset device
            print("Resetting device state")
            self.led_state = False
            self.relay_state = False
            self._update_status()
            
        elif cmd == 0x10:  # Set mode
            if len(command) >= 2:
                self.mode = command[1]
                print(f"Mode set to: {self.mode}")
                self._update_status()
    
    def _on_config(self, config):
        """Handle configuration updates"""
        if len(config) >= 2:
            # Example: First byte is config type, rest is data
            config_type = config[0]
            
            if config_type == 0x01:  # Update interval
                self.interval = struct.unpack('<H', config[1:3])[0]
                print(f"Update interval set to: {self.interval}ms")
                
            elif config_type == 0x02:  # Device name
                new_name = config[1:].decode('utf-8').strip('\x00')
                print(f"Device name updated to: {new_name}")
    
    def _send_sensor_data(self):
        """Send current sensor readings to mobile app"""
        # Pack sensor data: temperature (float), humidity (float), light (int)
        sensor_data = struct.pack('<ffi', self.temperature, self.humidity, self.light)
        self.ble_controller.update_sensor_data(sensor_data)
    
    def _update_status(self):
        """Update and send device status"""
        # Status: device_state, led_state, relay_state, mode
        status = (self.led_state << 0) | (self.relay_state << 1) | (self.mode << 2)
        self.ble_controller.update_device_status(
            status_code=status,
            state=1,  # Active
            battery=95,
            error=0
        )
    
    def update_sensors(self):
        """Simulate sensor reading updates"""
        import random
        self.temperature = 20.0 + random.random() * 10.0
        self.humidity = 40.0 + random.random() * 30.0
        self.light = int(300 + random.random() * 400)
        
        if self.ble_controller.is_connected():
            self._send_sensor_data()
    
    def run(self):
        """Main loop for the device"""
        print("Device running. Waiting for BLE connections...")
        last_update = time.ticks_ms()
        
        while True:
            current_time = time.ticks_ms()
            
            # Update sensors periodically
            if time.ticks_diff(current_time, last_update) >= self.interval:
                self.update_sensors()
                last_update = current_time
                
                # Print connection status
                if self.ble_controller.is_connected():
                    print(f"Connected clients: {self.ble_controller.get_connections_count()}")
                    print(f"Temp: {self.temperature:.1f}C, Humidity: {self.humidity:.1f}%, Light: {self.light}")
            
            time.sleep_ms(100)


